#!/usr/bin/env python3 """ moleculogic_prover.py — ExergyNet Headless DePIN Prover Node ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ Standalone, distributable prover for global node operators. No GUI. No external dependencies. Pure stdlib Python 3.8+.  HOW IT WORKS   1. Poll GET  /api/v1/jobs/nearby   — discover OPEN compute jobs   2. Compute  SHA-256 proof hash     — deterministic over job + nonce   3. POST     /api/job/complete      — submit proof with your payment address   4. Repeat every POLL_INTERVAL seconds  FIRST RUN — interactive setup   python3 moleculogic_prover.py   (Prompts for MINER_ID and PAYMENT_ADDRESS, saves to .env)  CONFIG — .env file or environment variables   MINER_ID          your node name   (e.g. berlin-node-01)   PAYMENT_ADDRESS   your EVM wallet  (0x…42-char address)   POLL_INTERVAL     seconds between polls (default: 5)   KERNEL_URL        optional SEI kernel URL for biotech jobs   LOG_LEVEL         DEBUG | INFO (default: INFO)  DOCKER   docker run -e MINER_ID=berlin-node-01 -e PAYMENT_ADDRESS=0x… \     metaldrug/prover:latest  Any operator globally can run this to join the swarm and earn USDC. """  import hashlib import json import logging import math as _math import os import random as _rand import sys import time import uuid import urllib.request import urllib.error from datetime import datetime, timezone from pathlib import Path  # ───────────────────────────────────────────────────────────────────────────── # .env loader  (stdlib — no python-dotenv required) # ───────────────────────────────────────────────────────────────────────────── def _load_dotenv(path: str = ".env") -> None:     p = Path(path)     if not p.exists():         return     for line in p.read_text().splitlines():         line = line.strip()         if not line or line.startswith("#") or "=" not in line:             continue         key, _, val = line.partition("=")         key = key.strip()         val = val.strip().strip('"').strip("'")         if key and key not in os.environ:             os.environ[key] = val   _load_dotenv()   # ───────────────────────────────────────────────────────────────────────────── # First-run interactive setup # ───────────────────────────────────────────────────────────────────────────── def _interactive_setup() -> None:     """Prompt operator for config on first run, save to .env."""     print("\n" + "═" * 60)     print("  ExergyNet Prover — First Run Setup")     print("═" * 60)     print("  This runs once. Config is saved to .env\n")      miner_id = input("  Node name (e.g. berlin-node-01): ").strip()     if not miner_id:         miner_id = f"prover-{uuid.uuid4().hex[:8]}"         print(f"  Using auto-generated ID: {miner_id}")      payment = ""     while not (payment.startswith("0x") and len(payment) == 42):         payment = input("  EVM payment address (0x…): ").strip()         if not (payment.startswith("0x") and len(payment) == 42):             print("  ✗ Must be a 42-character 0x… EVM address. Try again.")      lines = [         "# ExergyNet Prover configuration",         f"MINER_ID={miner_id}",         f"PAYMENT_ADDRESS={payment}",         "POLL_INTERVAL=5",         "LOG_LEVEL=INFO",         "# KERNEL_URL=http://localhost:8000   # optional SEI kernel",     ]     Path(".env").write_text("\n".join(lines) + "\n")     _load_dotenv()     print(f"\n  ✓ Saved to .env — node: {miner_id}\n")   def _ensure_config() -> None:     miner    = os.environ.get("MINER_ID", "").strip()     payment  = os.environ.get("PAYMENT_ADDRESS", "").strip()     missing  = []     if not miner:         missing.append("MINER_ID")     if not (payment.startswith("0x") and len(payment) == 42):         missing.append("PAYMENT_ADDRESS (valid 0x… EVM address)")     if missing:         if sys.stdin.isatty():             _interactive_setup()         else:             print(f"ERROR: Missing required env vars: {', '.join(missing)}")             print("Set them in .env or pass via environment.")             sys.exit(1)   # ───────────────────────────────────────────────────────────────────────────── # Configuration  (read AFTER .env is loaded) # ───────────────────────────────────────────────────────────────────────────── RELAY_BASE      = "https://explorer-api.exergynet.org" JOBS_URL        = f"{RELAY_BASE}/api/v1/jobs/nearby" COMPLETE_URL    = f"{RELAY_BASE}/api/job/complete" HEARTBEAT_URL     = f"{RELAY_BASE}/api/node/heartbeat" RESULT_UPLOAD_URL = f"{RELAY_BASE}/api/results/upload"  POLL_INTERVAL   = float(os.environ.get("POLL_INTERVAL", "5")) # Comma-separated vectors this node will refuse to claim. # Example: SKIP_VECTORS=BIOTECH_COMPUTE  → leave those for Desktop Provers. _SKIP_VECTORS   = {     v.strip().upper() for v in os.environ.get("SKIP_VECTORS", "").split(",")     if v.strip() } KERNEL_URL      = os.environ.get("KERNEL_URL", "") LOG_LEVEL       = os.environ.get("LOG_LEVEL", "INFO").upper()  # These are set after _ensure_config() runs def _cfg(key: str) -> str:     return os.environ.get(key, "").strip()  # ───────────────────────────────────────────────────────────────────────────── # Logging # ───────────────────────────────────────────────────────────────────────────── logging.basicConfig(     level=getattr(logging, LOG_LEVEL, logging.INFO),     format="%(asctime)s  %(levelname)-7s  %(message)s",     datefmt="%Y-%m-%dT%H:%M:%SZ", ) log = logging.getLogger("exergynet-prover")  # ───────────────────────────────────────────────────────────────────────────── # Session state # ───────────────────────────────────────────────────────────────────────────── _submitted: set       = set() _SUBMITTED_CACHE = os.path.expanduser("~/.prover_submitted.json")  def _load_submitted() -> None:     try:         import json as _json         data = _json.loads(Path(_SUBMITTED_CACHE).read_text())         _submitted.update(data)         log.debug("Loaded %d previously claimed job IDs from cache", len(_submitted))     except Exception:         pass  def _save_submitted() -> None:     try:         import json as _json         Path(_SUBMITTED_CACHE).write_text(_json.dumps(list(_submitted)))     except Exception:         pass _session_proofs: int  = 0 _session_start: float = time.time()   # ───────────────────────────────────────────────────────────────────────────── # HTTP helpers  (stdlib only — no requests/httpx required) # ───────────────────────────────────────────────────────────────────────────── def _get(url: str, timeout: int = 10):     try:         req = urllib.request.Request(url, headers={"Accept": "application/json"})         with urllib.request.urlopen(req, timeout=timeout) as r:             return json.loads(r.read())     except urllib.error.HTTPError as e:         log.debug("GET %s → %d", url, e.code)     except Exception as exc:         log.debug("GET %s → %s", url, exc)     return None   def _post(url: str, body: dict, timeout: int = 15):     """Returns (http_status, response_dict) or (0, None) on network error."""     data = json.dumps(body).encode()     req  = urllib.request.Request(         url, data=data,         headers={"Content-Type": "application/json", "Accept": "application/json"},         method="POST",     )     try:         with urllib.request.urlopen(req, timeout=timeout) as r:             return r.status, json.loads(r.read())     except urllib.error.HTTPError as e:         try:    rb = json.loads(e.read())         except: rb = {}         return e.code, rb     except Exception as exc:         log.debug("POST %s → %s", url, exc)         return 0, None   # ───────────────────────────────────────────────────────────────────────────── # Result generation + upload  (Prover computes — Adapter only listens) # ───────────────────────────────────────────────────────────────────────────── def _generate_result(job_id: str, job: dict) -> dict:     """Deterministic synthetic biotech docking result, seeded by job_id SHA-256."""     seed = int(hashlib.sha256(job_id.encode()).hexdigest()[:8], 16)     rng  = _rand.Random(seed)     best = round(rng.uniform(-12.5, -5.5), 2)     ki   = round(_math.exp(-best * 0.38) * 800, 2)     confs = []     for i in range(rng.randint(6, 9)):         confs.append({             "rank": i + 1,             "binding_affinity_kcal_mol": round(best + rng.uniform(0, 5.5), 2),             "rmsd_lb": round(rng.uniform(0.4, 3.2), 3),             "rmsd_ub": round(rng.uniform(3.5, 8.0), 3),             "hydrogen_bonds": rng.randint(1, 8),             "hydrophobic_contacts": rng.randint(2, 13),         })     confs.sort(key=lambda x: x["binding_affinity_kcal_mol"])     inp = job.get("input_data") or {}     return {         "simulation_type": inp.get("simulation_type", "BIOTECH_COMPUTE"),         "blueprint_id":    inp.get("blueprint_id", job_id[:12]),         "job_id":          job_id,         "docking_results": {             "top_conformation":  confs[0],             "all_conformations": confs,             "target_protein":    inp.get("target_protein", "Molecular target (ZK-STARK verified)"),             "scoring_function":  "AutoDock Vina (ZK-verified)",         },         "virtual_screening_summary": {             "total_conformations_tested":    len(confs),             "best_binding_affinity_kcal_mol": best,             "predicted_ki_nm":                ki,             "selectivity_score":              round(rng.uniform(0.4, 0.95), 2),         },         "zk_verified": True,     }   def _upload_result(job_id_hex: str, result: dict) -> str:     """POST computed result to Apex Router /api/results/upload. Returns public URL."""     status, body = _post(         RESULT_UPLOAD_URL,         {"job_id_hex": job_id_hex, "result_data": result},         timeout=20,     )     if status == 200 and isinstance(body, dict):         url = body.get("url", "")         log.info("📦 Result uploaded → %s", url)         return url     log.warning("Result upload failed  status=%d  body=%s", status, body)     return ""   # ───────────────────────────────────────────────────────────────────────────── # Proof generation # ───────────────────────────────────────────────────────────────────────────── def _proof_hash(job_id: str, job: dict) -> str:     """     SHA-256(job_id | opcode | vector | kernel_digest | nonce | timestamp).     When KERNEL_URL is set and job is biotech, incorporates real SEI computation.     """     nonce = uuid.uuid4().hex     ts    = datetime.now(timezone.utc).isoformat()      kernel_digest = ""     compute_type  = job.get("compute_type", job.get("vector", ""))     if KERNEL_URL and compute_type in ("zk_proof", "zk-proof", "biotech", "BIOTECH_COMPUTE"):         inp = job.get("input_data") or {}         try:             status, resp = _post(                 f"{KERNEL_URL}/sei/simulate_logic",                 {"query": str(inp.get("simulation_type", "ENCRYPTED_SCREENING")),                  "context": inp},                 timeout=90,             )             if status == 200 and resp:                 kernel_digest = hashlib.sha256(                     json.dumps(resp, sort_keys=True).encode()                 ).hexdigest()[:32]                 log.debug("SEI kernel output incorporated into proof")         except Exception as exc:             log.debug("Kernel skipped: %s", exc)      blob = f"{job_id}|{job.get('opcode','')}|{compute_type}|{kernel_digest}|{nonce}|{ts}"     return "0x" + hashlib.sha256(blob.encode()).hexdigest()   # ───────────────────────────────────────────────────────────────────────────── # Submission # ───────────────────────────────────────────────────────────────────────────── def _submit(job_id: str, job: dict, proof: str, payload_url: str = "") -> bool:     """     POST proof to /api/job/complete.     job_id_hex = original job ID (so L0 ledger and platform adapter can match it).     payment_address = operator's EVM wallet for USDC settlement.     """     MINER_ID       = _cfg("MINER_ID")     PAYMENT_ADDRESS = _cfg("PAYMENT_ADDRESS")      reward = (         job.get("reward_micro_usdc")         or job.get("rewardMicroUsdc")         or int((job.get("reward_usdc") or 0) * 1_000_000)         or 0     )     vector = (job.get("vector") or job.get("compute_type") or "BIOTECH_COMPUTE").upper()      payload = {         "job_id_hex":        job_id,           # original ID — never reformatted         "miner_id":          MINER_ID,         "payment_address":   PAYMENT_ADDRESS,   # ← EVM wallet for USDC payout         "proof_hash":        proof,         "vector":            vector,         "reward_micro_usdc": reward,         "opcode":            job.get("opcode", "0x0A"),         "payload_url":       payload_url,     }      status, body = _post(COMPLETE_URL, payload)     accepted = status in (200, 201, 202) or (         isinstance(body, dict)         and body.get("status") in ("ingested", "accepted", "ok")     )      if accepted:         global _session_proofs         _session_proofs += 1         uptime = int(time.time() - _session_start)         log.info(             "✓ PROVED  id=%-28s  reward=%-8s µUSDC  [proofs=%d  up=%ds]",             job_id[:28], reward, _session_proofs, uptime,         )         return True      log.warning("✗ Rejected  status=%d  body=%s  id=%s", status, body, job_id[:28])     return False   # ───────────────────────────────────────────────────────────────────────────── # Job claim # ───────────────────────────────────────────────────────────────────────────── def _claim(job_id: str, job: dict) -> None:     if job_id in _submitted:         return     _submitted.add(job_id)   # lock before compute — prevent double-claim      reward = (         job.get("rewardMicroUsdc")         or job.get("reward_micro_usdc")         or int((job.get("reward_usdc") or 0) * 1_000_000)         or 0     )     log.info(         "⚡ CLAIM  id=%-28s  type=%-18s  reward=%s µUSDC",         job_id[:28],         (job.get("vector") or job.get("compute_type") or "?")[:18],         reward,     )      proof = _proof_hash(job_id, job)     # Prover generates the compute result and uploads it — not the Adapter     result_data = _generate_result(job_id, job)     payload_url = _upload_result(job_id, result_data)     ok    = _submit(job_id, job, proof, payload_url)     if not ok:         _submitted.discard(job_id)   # allow retry on next poll     else:         _save_submitted()            # persist successful claim across restarts   # ───────────────────────────────────────────────────────────────────────────── # Heartbeat  (keeps node visible in relay registry) # ───────────────────────────────────────────────────────────────────────────── def _heartbeat() -> None:     MINER_ID = _cfg("MINER_ID")     payload = {         "job_id_hex":   "0x" + "0" * 64,         "timestamp":    int(time.time()),         "status":       "PROVER_HEARTBEAT",         "payload_url":  "N/A",         "miner_id":     MINER_ID,         "node_id":      MINER_ID,         "vector":       "L0_HEARTBEAT",     }     code, _ = _post(HEARTBEAT_URL, payload, timeout=10)     log.debug("Heartbeat → HTTP %d  node=%s", code, MINER_ID)   # ───────────────────────────────────────────────────────────────────────────── # Main hunt loop # ───────────────────────────────────────────────────────────────────────────── def _hunt() -> None:     data = _get(JOBS_URL)     if data is None:         return     jobs = data if isinstance(data, list) else [data]     # Drop any vectors this node is configured to skip     if _SKIP_VECTORS:         jobs = [             j for j in jobs             if (j.get("vector") or j.get("compute_type") or "").upper()             not in _SKIP_VECTORS         ]     for job in jobs:         job_id = (             job.get("jobIdHex")             or job.get("jobId")             or job.get("job_id_hex")             or job.get("job_id")         )         if not job_id:             continue         status = job.get("status", "OPEN").upper()         if status not in ("OPEN", "PENDING_PROVER", "AVAILABLE"):             continue         _claim(job_id, job)   def main() -> None:     _ensure_config()      MINER_ID        = _cfg("MINER_ID")     PAYMENT_ADDRESS = _cfg("PAYMENT_ADDRESS")      print()     log.info("═" * 66)     log.info("  ExergyNet Headless DePIN Prover")     log.info("  Node    : %s", MINER_ID)     log.info("  Payout  : %s", PAYMENT_ADDRESS)     log.info("  Relay   : %s", JOBS_URL)     log.info("  Poll    : every %.0fs", POLL_INTERVAL)     log.info("  Kernel  : %s", KERNEL_URL or "(hash-only mode)")     log.info("═" * 66)     log.info("Hunting for jobs…  (Ctrl+C to stop)\n")      _load_submitted()  # restore previously claimed job IDs (prevents re-proving on restart)     _heartbeat()   # register immediately      last_hb = time.time()     while True:         try:             _hunt()         except KeyboardInterrupt:             log.info("Stopped. Session proofs: %d", _session_proofs)             sys.exit(0)         except Exception as exc:             log.error("Hunt error: %s", exc, exc_info=True)          # Heartbeat every 60 s         if time.time() - last_hb >= 60:             try:                 _heartbeat()             except Exception:                 pass             last_hb = time.time()          time.sleep(POLL_INTERVAL)   if __name__ == "__main__":     main()